quizDraft.solutionCode:
def eligibility_checker(age, has_permission):
    if age >= 18 and has_permission:
        return 'Eligible'
    else:
        return 'Not Eligible'

# Test cases
print(eligibility_checker(20, True))  # Eligible
print(eligibility_checker(16, False))  # Not Eligible
